import sqlite3
from contextlib import closing

app = Flask(__name__)

MEMCACHED_HOST = os.getenv("MEMCACHED_HOST", "localhost")
MEMCACHED_PORT = int(os.getenv("MEMCACHED_PORT", "11211"))
DB_PATH = os.getenv("DB_PATH", "app.db")

memcached_client = Client((MEMCACHED_HOST, MEMCACHED_PORT), connect_timeout=1, timeout=1)


def get_db_connection():
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    return conn


def make_cache_key(prefix, value):
    raw = f"{prefix}:{value}"
    digest = hashlib.sha256(raw.encode("utf-8")).hexdigest()
    return f"{prefix}:{digest}"


def cache_get_json(key):
    try:
        cached = memcached_client.get(key)
        if cached is None:
            return None
        if isinstance(cached, bytes):
            cached = cached.decode("utf-8")
        return json.loads(cached)
    except Exception:
        return None


def cache_set_json(key, value, ttl):
    try:
        memcached_client.set(key, json.dumps(value).encode("utf-8"), expire=ttl)
    except Exception:
        pass


@app.route("/api/users/<int:user_id>", methods=["GET"])
def get_user(user_id):
    cache_key = make_cache_key("api:user", user_id)
    cached_response = cache_get_json(cache_key)
    if cached_response is not None:
        return jsonify(cached_response)

